package pages

import (
	"context"
	"fmt"
	"github.com/a-h/templ"
	"io"
	"strconv"
)

const appDetailPaasScript = `<script>function appId(){const root=document.getElementById('app-detail-root');return root?root.dataset.appId||'':'';}async function runAppAction(action){const feedback=document.getElementById('app-feedback');const id=appId();if(feedback)feedback.textContent='Running '+action+'...';const response=await fetch('/api/apps/'+encodeURIComponent(id)+'/'+action,{method:'POST'});const payload=await response.json().catch(()=>({}));if(!response.ok){if(feedback)feedback.textContent=payload.error||'Action failed';return;}window.location.reload();}async function deleteApp(){if(!confirm('Delete this application? All containers, volumes, and files will be permanently removed.'))return;const feedback=document.getElementById('app-feedback');const id=appId();if(feedback)feedback.textContent='Deleting...';const response=await fetch('/api/apps/'+encodeURIComponent(id),{method:'DELETE'});const payload=await response.json().catch(()=>({}));if(!response.ok){if(feedback)feedback.textContent=payload.error||'Delete failed';return;}window.location.href='/apps';}function renderManagedEnv(env){if(!env||typeof env!=='object')return '';return Object.entries(env).map(([key,value])=>key+'='+value).join('\n');}function parseManagedEnv(text){const values={};const lines=text.split('\n');for(const raw of lines){const line=raw.trim();if(!line||line.startsWith('#'))continue;const separator=line.indexOf('=');if(separator<=0)continue;const key=line.slice(0,separator).trim();const value=line.slice(separator+1).trim();if(!key)continue;values[key]=value;}return values;}async function loadAppConfig(){const response=await fetch('/api/apps/'+encodeURIComponent(appId())+'/config',{method:'GET'});const payload=await response.json().catch(()=>({}));if(!response.ok)return;document.getElementById('app-public-domain').value=payload.public_domain||'';document.getElementById('app-proxy-target-port').value=payload.proxy_target_port?String(payload.proxy_target_port):'';document.getElementById('app-use-tls').checked=!!payload.use_tls;document.getElementById('app-managed-env').value=renderManagedEnv(payload.managed_env||{});}async function saveAppConfig(){const feedback=document.getElementById('app-config-feedback');if(feedback)feedback.textContent='Saving app settings...';const request={public_domain:document.getElementById('app-public-domain').value.trim(),proxy_target_port:Number.parseInt(document.getElementById('app-proxy-target-port').value,10)||0,use_tls:!!document.getElementById('app-use-tls').checked,managed_env:parseManagedEnv(document.getElementById('app-managed-env').value)};const response=await fetch('/api/apps/'+encodeURIComponent(appId())+'/config',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(request)});const payload=await response.json().catch(()=>({}));if(!response.ok){if(feedback)feedback.textContent=payload.error||'Failed to save app settings';return;}if(feedback)feedback.textContent='App settings saved';await loadAppConfig();}document.addEventListener('DOMContentLoaded',loadAppConfig);</script>`

const composeScript = `<script>function composeRoot(){return document.getElementById('compose-root');}function currentAppID(){const root=composeRoot();return root?root.dataset.appId||'':'';}function initialMode(){const root=composeRoot();const sourceType=root?root.dataset.sourceType||'':'';return sourceType==='repo_compose'||sourceType==='repo_dockerfile'?'repo':'compose';}const composeModeNode=document.getElementById('compose-mode');const repoModeNode=document.getElementById('repo-mode');const composeTabNode=document.getElementById('tab-compose');const repoTabNode=document.getElementById('tab-repo');const statusNode=document.getElementById('compose-status');function setMode(mode){const isRepo=mode==='repo';composeModeNode.classList.toggle('hidden',isRepo);repoModeNode.classList.toggle('hidden',!isRepo);composeTabNode.classList.toggle('bg-card',!isRepo);repoTabNode.classList.toggle('bg-card',isRepo);}function toInt(value){const parsed=Number.parseInt(value,10);return Number.isFinite(parsed)?parsed:0;}function isReservedIngressPort(port){return port===80||port===443;}async function saveCompose(shouldDeploy){if(statusNode)statusNode.textContent=shouldDeploy?'Saving and deploying...':'Saving...';const appName=document.getElementById('app-name').value.trim();const usingRepoMode=!repoModeNode.classList.contains('hidden');const appID=currentAppID();if(appName===''){if(statusNode)statusNode.textContent='App name is required';return;}if(usingRepoMode){const repoURL=document.getElementById('repo-url').value.trim();const composePath=document.getElementById('repo-compose-path').value.trim();const repoPort=toInt(document.getElementById('repo-app-port').value);if(!repoURL){if(statusNode)statusNode.textContent='Repository URL is required';return;}if(!composePath&&repoPort<=0){if(statusNode)statusNode.textContent='App port is required when compose path is not provided';return;}if(!composePath&&isReservedIngressPort(repoPort)){if(statusNode)statusNode.textContent='App port 80/443 is reserved for platform ingress';return;}if(appID){if(statusNode)statusNode.textContent='Import mode updates existing applications are disabled';return;}}const endpoint=usingRepoMode?'/api/apps/import':(appID?'/api/apps/'+encodeURIComponent(appID):'/api/apps');const method=appID?'PUT':'POST';let requestInit;if(usingRepoMode){requestInit={method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:appName,repo_url:document.getElementById('repo-url').value.trim(),branch:document.getElementById('repo-branch').value.trim(),compose_path:document.getElementById('repo-compose-path').value.trim(),app_port:toInt(document.getElementById('repo-app-port').value),auto_deploy:document.getElementById('repo-auto-deploy').checked||false})};}else{requestInit={method:method,headers:{'Content-Type':'application/json'},body:JSON.stringify({name:appName,compose_yaml:document.getElementById('compose-yaml').value})};}const response=await fetch(endpoint,requestInit);const payload=await response.json().catch(()=>({}));if(!response.ok){if(statusNode)statusNode.textContent=payload.error||'Save failed';return;}if(!shouldDeploy){if(usingRepoMode&&!appID){window.location.href='/apps';return;}window.location.href='/apps/'+encodeURIComponent(payload.id)+'/compose';return;}const resolvedID=payload.id||appID;if(!resolvedID){if(statusNode)statusNode.textContent='App created but no ID was returned';return;}if(!usingRepoMode&&appID){const deployResponse=await fetch('/api/apps/'+encodeURIComponent(resolvedID)+'/deploy',{method:'POST'});const deployPayload=await deployResponse.json().catch(()=>({}));if(!deployResponse.ok){if(statusNode)statusNode.textContent=deployPayload.error||'Deploy failed';return;}}window.location.href='/apps/'+encodeURIComponent(resolvedID);}setMode(initialMode());</script>`

const logsScript = `<script>function logsAppId(){const root=document.getElementById('logs-root');return root?root.dataset.appId||'':'';}async function loadAppLogs(){const logsNode=document.getElementById('app-logs-content');const feedback=document.getElementById('app-feedback');if(feedback)feedback.textContent='Loading logs...';const response=await fetch('/api/apps/'+encodeURIComponent(logsAppId())+'/logs?lines=100');const payload=await response.json().catch(()=>({}));if(!response.ok){if(logsNode)logsNode.textContent=payload.error||'Failed to load logs';if(feedback)feedback.textContent='Unable to fetch logs';return;}if(logsNode)logsNode.textContent=payload.logs||'No logs yet';if(feedback)feedback.textContent='Status: '+(payload.status||'unknown');}document.addEventListener('DOMContentLoaded',loadAppLogs);</script>`

const settingsScript = `<script>async function loadAdminSettings(){const response=await fetch('/api/settings',{method:'GET'});const payload=await response.json().catch(()=>({}));if(!response.ok)return;document.getElementById('admin-host').value=payload.admin_host||'';document.getElementById('admin-port').value=payload.admin_port?String(payload.admin_port):'';document.getElementById('admin-domain').value=payload.admin_domain||'';document.getElementById('admin-use-tls').checked=!!payload.admin_use_tls;document.getElementById('certbot-email').value=payload.certbot_email||'';document.getElementById('certbot-enabled').checked=!!payload.certbot_enabled;document.getElementById('certbot-staging').checked=!!payload.certbot_staging;document.getElementById('certbot-auto-renew').checked=payload.certbot_auto_renew!==false;document.getElementById('certbot-terms').checked=!!payload.certbot_terms_accepted;}async function saveAdminSettings(){const feedback=document.getElementById('admin-settings-feedback');if(feedback)feedback.textContent='Saving settings...';const payload={admin_host:document.getElementById('admin-host').value.trim(),admin_port:Number.parseInt(document.getElementById('admin-port').value,10)||0,admin_domain:document.getElementById('admin-domain').value.trim(),admin_use_tls:!!document.getElementById('admin-use-tls').checked,certbot_email:document.getElementById('certbot-email').value.trim(),certbot_enabled:!!document.getElementById('certbot-enabled').checked,certbot_staging:!!document.getElementById('certbot-staging').checked,certbot_auto_renew:!!document.getElementById('certbot-auto-renew').checked,certbot_terms_accepted:!!document.getElementById('certbot-terms').checked};const response=await fetch('/api/settings',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const body=await response.json().catch(()=>({}));if(!response.ok){if(feedback)feedback.textContent=body.error||'Failed to save settings';return;}if(feedback)feedback.textContent='Settings saved';await loadAdminSettings();}async function renewCertificates(){const feedback=document.getElementById('certbot-renew-feedback');if(feedback)feedback.textContent='Running renewal...';const response=await fetch('/api/certificates/renew',{method:'POST'});const body=await response.json().catch(()=>({}));if(!response.ok){if(feedback)feedback.textContent=body.error||'Certificate renewal failed';return;}if(feedback)feedback.textContent=body.message||'Certificate renewal completed';}document.addEventListener('DOMContentLoaded',loadAdminSettings);</script>`

const scanScript = `<script>window.toggleScanRow=function(rowId){const row=document.getElementById(rowId);if(!row)return;row.classList.toggle('hidden');};window.copyScanCommands=async function(outputId){const target=document.getElementById(outputId);if(!target)return;try{await navigator.clipboard.writeText(target.textContent||'');}catch(err){console.error('Copy failed:',err);}};</script>`

func AppDetailPaasPage(data AppDetailPaasView) templ.Component {
	return pageShell(data.LayoutData, templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		if err := write(w, `<section id="app-detail-root" data-app-id="`+esc(data.ID)+`" class="space-y-4"><div class="flex items-start justify-between gap-3"><div><div class="text-sm text-muted-foreground">App ID: `+esc(data.ID)+`</div><h2 class="text-2xl font-semibold">`+esc(data.Name)+`</h2></div>`); err != nil {
			return err
		}
		if err := renderStatusBadge(w, data.Status); err != nil {
			return err
		}
		return write(w, `</div><div class="grid gap-3 md:grid-cols-2"><div class="card card-content space-y-2"><div class="font-semibold">Runtime</div><p class="text-sm text-muted-foreground">Stack directory: `+esc(data.Dir)+`</p><p class="text-sm text-muted-foreground">Ports: `+esc(data.PortsStr)+`</p><p class="text-sm text-muted-foreground">Updated: `+esc(data.UpdatedAt)+`</p></div><div class="card card-content space-y-3"><div class="font-semibold">Public access</div><label class="block text-sm text-muted-foreground">Public domain<input id="app-public-domain" type="text" class="form-input" placeholder="app.example.com"/></label><p class="text-xs text-muted-foreground">Traffic starts as HTTP by default on the configured domain.</p><label class="block text-sm text-muted-foreground">Proxy target port<input id="app-proxy-target-port" type="number" min="1" max="65535" class="form-input" placeholder="3000"/></label><p class="text-xs text-muted-foreground">Use the internal container port that the host nginx proxy should target on the managed Docker network.</p><label class="flex items-center gap-2 text-sm"><input id="app-use-tls" type="checkbox"/><span>Enable HTTPS on proxy</span></label><p class="text-xs text-muted-foreground">Enable HTTPS only after valid Let's Encrypt settings are configured; otherwise the app remains available on HTTP.</p><label class="block text-sm text-muted-foreground">Managed environment variables<textarea id="app-managed-env" class="mt-1 w-full rounded border border-border bg-background p-2 text-sm" rows="6"></textarea></label><button type="button" class="rounded border border-border px-4 py-2 text-sm" onclick="saveAppConfig()">Save app settings</button><div id="app-config-feedback" class="text-sm text-muted-foreground"></div></div><div class="card card-content space-y-3"><div class="font-semibold">Actions</div><div class="flex flex-wrap gap-2"><button class="rounded border border-border px-4 py-2 text-sm" onclick="runAppAction('deploy')">Deploy</button><button class="rounded border border-border px-4 py-2 text-sm" onclick="runAppAction('restart')">Restart</button><button class="rounded border border-border px-4 py-2 text-sm" onclick="runAppAction('stop')">Stop</button></div><div class="mt-2"><button class="rounded border border-destructive px-4 py-2 text-sm text-destructive" onclick="deleteApp()">Delete</button></div><div id="app-feedback" class="text-sm text-muted-foreground"></div><div class="flex flex-wrap gap-2"><a href="/apps/`+esc(data.ID)+`/compose" class="rounded border border-border px-4 py-2 text-sm">Compose</a><a href="/apps/`+esc(data.ID)+`/logs" class="rounded border border-border px-4 py-2 text-sm">Logs</a></div></div></div>`+appDetailPaasScript+`</section>`)
	}))
}

func ComposePage(data ComposeView) templ.Component {
	return pageShell(data.LayoutData, templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		appPort := ""
		if data.AppPort > 0 {
			appPort = strconv.Itoa(data.AppPort)
		}
		return write(w, `<section id="compose-root" data-app-id="`+esc(data.AppID)+`" data-source-type="`+esc(data.SourceType)+`" class="space-y-4"><div><div class="text-sm text-muted-foreground">`+esc(data.Subtitle)+`</div><div class="text-2xl font-semibold">`+esc(data.Title)+`</div></div><div class="grid gap-3 lg:grid-cols-[2fr_1fr]"><div class="card card-content space-y-3"><div class="flex gap-2"><button id="tab-compose" type="button" class="rounded border px-4 py-1.5 text-sm" onclick="setMode('compose')">Compose YAML</button><button id="tab-repo" type="button" class="rounded border px-4 py-1.5 text-sm" onclick="setMode('repo')">Import from Git repo</button></div><div class="font-semibold">Compose pack</div><form id="compose-form" class="space-y-3"><div><label class="form-label">App name</label><input id="app-name" class="form-input" value="`+esc(data.Name)+`"/></div><div id="compose-mode"><label class="form-label">Docker Compose YAML</label><textarea id="compose-yaml" class="mt-1 w-full rounded border border-border bg-background p-2 text-sm" rows="18">`+esc(data.ComposeYAML)+`</textarea></div><div id="repo-mode" class="space-y-3"><div><label class="form-label">Repository URL</label><input id="repo-url" type="text" class="form-input" value="`+esc(data.RepoURL)+`" placeholder="https://github.com/owner/repository.git"/></div><div><label class="form-label">Branch</label><input id="repo-branch" type="text" class="form-input" value="`+esc(data.RepoBranch)+`" placeholder="main"/></div><div><label class="form-label">Compose file path (optional)</label><input id="repo-compose-path" type="text" class="form-input" value="`+esc(data.ComposePath)+`" placeholder="docker-compose.yml or compose.yml"/></div><div><label class="form-label">App port (required for Dockerfile fallback)</label><input id="repo-app-port" type="number" min="1" max="65535" class="form-input" value="`+esc(appPort)+`" placeholder="3000"/><div class="text-xs text-muted-foreground">If compose file is not provided, this value is mapped to generated Compose as HOST:CONTAINER.</div></div><label class="flex items-center gap-2 text-sm"><input id="repo-auto-deploy" type="checkbox" checked/><span>Deploy immediately after import</span></label></div><div id="compose-status" class="text-sm text-muted-foreground"></div><div class="flex flex-wrap gap-2"><button type="button" class="rounded border border-border px-4 py-2 text-sm" onclick="saveCompose(false)">`+esc(data.ActionLabel)+`</button><button type="button" class="rounded border border-border px-4 py-2 text-sm" onclick="saveCompose(true)">Deploy now</button></div></form></div><div class="card card-content space-y-2"><div class="font-semibold">Shortcuts</div><p class="text-sm text-muted-foreground">Do not use the obsolete <code>version:</code> key.</p><p class="text-sm text-muted-foreground">Use <code>command:</code> instead of <code>args:</code> for passing arguments to containers.</p><p class="text-sm text-muted-foreground">When import mode is selected, the system clones your public repo and validates compose file if present.</p><p class="text-sm text-muted-foreground">Expose only non-ingress ports in compose mappings. Ports <code>80</code> and <code>443</code> are reserved for the platform ingress.</p><p class="text-sm text-muted-foreground">If no compose file is found, fallback uses Dockerfile + generated Compose, requiring an explicit port that is not <code>80</code> or <code>443</code>.</p></div></div>`+composeScript+`</section>`)
	}))
}

func LogsPage(data LogsView) templ.Component {
	return pageShell(data.LayoutData, templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		return write(w, `<section id="logs-root" data-app-id="`+esc(data.ID)+`" class="space-y-4"><div><div class="text-sm text-muted-foreground">`+esc(data.ID)+`</div><div class="text-2xl font-semibold">`+esc(data.Name)+` logs</div><div class="text-sm text-muted-foreground">Recent runtime log output</div></div><div id="app-feedback" class="text-sm text-muted-foreground"></div><div class="flex gap-2"><button onclick="loadAppLogs()" class="rounded border border-border px-4 py-2 text-sm">Refresh</button><a href="/apps/`+esc(data.ID)+`/compose" class="rounded border border-border px-4 py-2 text-sm">Open compose</a></div><div class="card card-content overflow-x-auto"><pre id="app-logs-content" class="whitespace-pre-wrap text-xs text-muted-foreground">`+esc(data.LogsContent)+`</pre></div>`+logsScript+`</section>`)
	}))
}

func SettingsPage(data LayoutData) templ.Component {
	return pageShell(data, templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		return write(w, `<section class="space-y-4"><div><div class="text-2xl font-semibold">Settings</div><div class="text-sm text-muted-foreground">Manage platform endpoint settings used by the admin API and external access.</div></div><div class="grid gap-3 md:grid-cols-2"><div class="card card-content"><div class="font-semibold">Admin panel endpoint</div><div class="space-y-3"><label class="block text-sm text-muted-foreground">Admin host<input id="admin-host" class="form-input" placeholder="0.0.0.0"/></label><label class="block text-sm text-muted-foreground">Admin port<input id="admin-port" type="number" min="1" max="65535" class="form-input" placeholder="3000"/></label><label class="block text-sm text-muted-foreground">Admin domain (optional)<input id="admin-domain" class="form-input" placeholder="dashboard.example.com"/></label><label class="flex items-center gap-2 text-sm"><input id="admin-use-tls" type="checkbox"/><span>Enable HTTPS for admin endpoint</span></label><label class="block text-sm text-muted-foreground">Let's Encrypt email<input id="certbot-email" class="form-input" placeholder="admin@example.com"/></label><label class="flex items-center gap-2 text-sm"><input id="certbot-enabled" type="checkbox"/><span>Enable certificate automation</span></label><label class="flex items-center gap-2 text-sm"><input id="certbot-staging" type="checkbox"/><span>Use Let's Encrypt staging environment</span></label><label class="flex items-center gap-2 text-sm"><input id="certbot-auto-renew" type="checkbox" checked/><span>Enable automatic renewal</span></label><p class="mt-1 text-xs text-muted-foreground">Renewal uses the host-installed <code>certbot</code> binary through the dashboard controller container. If you disable automatic renewal, add a manual renewal schedule and keep host <code>nginx</code> reload enabled after renewal.</p><label class="flex items-center gap-2 text-sm"><input id="certbot-terms" type="checkbox"/><span>I accept Let's Encrypt terms of service</span></label><button type="button" class="rounded border border-border px-4 py-2 text-sm" onclick="saveAdminSettings()">Save admin settings</button><div id="admin-settings-feedback" class="text-sm text-muted-foreground"></div><button type="button" class="rounded border border-border px-4 py-2 text-sm" onclick="renewCertificates()">Run certificate renewal now</button><div id="certbot-renew-feedback" class="text-sm text-muted-foreground"></div></div></div><div class="card card-content"><div class="font-semibold">Notes</div><ul class="list-inside list-disc space-y-2 text-sm text-muted-foreground"><li>Platform exposes this config through <code>/api/settings</code>.</li><li>When domain is not set, the panel is reachable via host IP.</li><li>TLS settings are applied only when "Enable HTTPS on proxy" is enabled for an app.</li><li>Certificates are issued and removed against the host installation of <code>certbot</code>.</li><li>Host <code>nginx</code> owns ports 80/443 and keeps routing active even if the dashboard container is removed.</li></ul></div></div>`+settingsScript+`</section>`)
	}))
}

func ScanPage(data ScanView) templ.Component {
	return pageShell(data.LayoutData, templ.ComponentFunc(func(ctx context.Context, w io.Writer) error {
		if err := write(w, `<section class="space-y-4"><div class="text-sm text-muted-foreground">Scanner reports all discovered Docker resources with safe cleanup hints.</div><div class="text-2xl font-semibold">Scanner</div><div class="text-xs text-muted-foreground">Last scan: `+esc(data.ScannedAt)+`</div><div class="card card-content"><div class="text-sm text-muted-foreground">Stacks directory</div><div class="mt-1 text-sm">`+esc(data.StacksDir)+`</div></div><div class="grid gap-3 md:grid-cols-2 xl:grid-cols-6"><article class="card card-content"><div class="text-xs text-muted-foreground">Managed</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.Managed)+`</p></article><article class="card card-content"><div class="text-xs text-muted-foreground">Broken apps</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.Broken)+`</p></article><article class="card card-content"><div class="text-xs text-muted-foreground">Orphan dirs</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.OrphanDir)+`</p></article><article class="card card-content"><div class="text-xs text-muted-foreground">Orphan runtime</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.OrphanRuntime)+`</p></article><article class="card card-content"><div class="text-xs text-muted-foreground">Stale admin</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.StaleAdmin)+`</p></article><article class="card card-content"><div class="text-xs text-muted-foreground">Unknown</div><p class="text-2xl font-semibold">`+strconv.Itoa(data.Summary.Unknown)+`</p></article></div><div class="card"><div class="card-header"><div class="card-title">Discovered resources</div></div><div class="overflow-x-auto">`); err != nil {
			return err
		}
		if len(data.Resources) == 0 {
			return write(w, `<div class="p-4 text-sm text-muted-foreground">No resources discovered yet.</div></div></div>`+scanScript+`</section>`)
		}
		if err := write(w, `<table class="w-full"><thead class="bg-muted"><tr><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Name</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Kind</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Status</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Confidence</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Dir</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Containers</th><th class="min-w-0 px-4 py-2 text-left text-xs font-semibold text-muted-foreground">Reason</th></tr></thead><tbody class="divide-y divide-border">`); err != nil {
			return err
		}
		for i, r := range data.Resources {
			rowID := fmt.Sprintf("scan-row-%d", i)
			cmdID := fmt.Sprintf("scan-cmd-%d", i)
			if err := write(w, `<tr><td class="min-w-0 px-4 py-2 text-sm">`+esc(r.Name)+`</td><td class="min-w-0 px-4 py-2 text-sm">`+esc(r.Kind)+`</td><td class="min-w-0 px-4 py-2 text-sm">`+esc(r.Status)+`</td><td class="min-w-0 px-4 py-2 text-sm">`+esc(r.Confidence)+`</td><td class="min-w-0 px-4 py-2 text-sm text-muted-foreground">`+esc(r.Dir)+`</td><td class="min-w-0 px-4 py-2 text-sm text-muted-foreground">`+esc(JoinStrings(r.Containers, ", "))+`</td><td class="min-w-0 px-4 py-2 text-sm text-muted-foreground"><button class="rounded border border-border px-2 py-1 text-xs" onclick="toggleScanRow('`+rowID+`')">Details</button></td></tr><tr id="`+rowID+`" class="hidden"><td class="px-4 py-2" colspan="7"><div class="space-y-3"><div class="text-sm"><div class="font-semibold">Reason</div><div class="text-muted-foreground">`+esc(r.Reason)+`</div></div><div class="text-sm"><div class="font-semibold">Project</div><div class="text-muted-foreground">`+esc(r.ComposeProject)+`</div></div><div class="text-sm"><div class="font-semibold">Ports</div><div class="text-muted-foreground">`+esc(JoinStrings(r.Ports, ", "))+`</div></div>`); err != nil {
				return err
			}
			if r.IsCurrent {
				if err := write(w, `<div class="text-xs text-amber-500">This appears to be the currently running admin container.</div>`); err != nil {
					return err
				}
			}
			if err := write(w, `<div><div class="mb-1 text-sm font-semibold">Cleanup commands</div>`); err != nil {
				return err
			}
			if len(r.CleanupCmds) > 0 {
				if err := write(w, `<div class="relative"><button class="absolute right-2 top-2 rounded border border-border px-2 py-1 text-xs" onclick="copyScanCommands('`+cmdID+`')">Copy</button><pre id="`+cmdID+`" class="overflow-x-auto whitespace-pre-wrap rounded border border-border bg-muted px-4 py-2 text-xs">`+esc(JoinStrings(r.CleanupCmds, "\n"))+`</pre></div>`); err != nil {
					return err
				}
			} else {
				if err := write(w, `<div class="text-sm text-muted-foreground">No automatic command is suggested for this item.</div>`); err != nil {
					return err
				}
			}
			if err := write(w, `</div></div></td></tr>`); err != nil {
				return err
			}
		}
		return write(w, `</tbody></table></div></div>`+scanScript+`</section>`)
	}))
}
